3928 bool LoopVectorizationPlanner::isMoreProfitable(const VectorizationFactor &A,
3929                                                 const VectorizationFactor &B,
3930                                                 const unsigned MaxTripCount,
3931                                                 bool HasTail,
3932                                                 bool IsEpilogue) const {
3933   InstructionCost CostA = A.Cost;
3934   InstructionCost CostB = B.Cost;
3935 
3936   // Improve estimate for the vector width if it is scalable.
3937   unsigned EstimatedWidthA = A.Width.getKnownMinValue();
3938   unsigned EstimatedWidthB = B.Width.getKnownMinValue();
3939   if (std::optional<unsigned> VScale = CM.getVScaleForTuning()) {
3940     if (A.Width.isScalable())
3941       EstimatedWidthA *= *VScale;
3942     if (B.Width.isScalable())
3943       EstimatedWidthB *= *VScale;
3944   }
3945 
3946   // When there is a hint to always prefer scalable vectors,
3947   // honour that hint.
3948   if (Hints.isScalableVectorizationAlwaysPreferred())
3949     if (A.Width.isScalable() && A.Cost.isValid() && !B.Width.isScalable())
3950       return true;
3951 
3952   // When optimizing for size choose whichever is smallest, which will be the
3953   // one with the smallest cost for the whole loop. On a tie pick the larger
3954   // vector width, on the assumption that throughput will be greater.
3955   if (CM.CostKind == TTI::TCK_CodeSize)
3956     return CostA < CostB ||
3957            (CostA == CostB && EstimatedWidthA > EstimatedWidthB);
3958 
3959   // Assume vscale may be larger than 1 (or the value being tuned for),
3960   // so that scalable vectorization is slightly favorable over fixed-width
3961   // vectorization.
3962   bool PreferScalable = !TTI.preferFixedOverScalableIfEqualCost(IsEpilogue) &&
3963                         A.Width.isScalable() && !B.Width.isScalable();
3964 
3965   auto CmpFn = [PreferScalable](const InstructionCost &LHS,
3966                                 const InstructionCost &RHS) {
3967     return PreferScalable ? LHS <= RHS : LHS < RHS;
3968   };
3969 
3970   // To avoid the need for FP division:
3971   //      (CostA / EstimatedWidthA) < (CostB / EstimatedWidthB)
3972   // <=>  (CostA * EstimatedWidthB) < (CostB * EstimatedWidthA)
3973   if (!MaxTripCount)
3974     return CmpFn(CostA * EstimatedWidthB, CostB * EstimatedWidthA);
3975 
3976   auto GetCostForTC = [MaxTripCount, HasTail](unsigned VF,
3977                                               InstructionCost VectorCost,
3978                                               InstructionCost ScalarCost) {
3979     // If the trip count is a known (possibly small) constant, the trip count
3980     // will be rounded up to an integer number of iterations under
3981     // FoldTailByMasking. The total cost in that case will be
3982     // VecCost*ceil(TripCount/VF). When not folding the tail, the total
3983     // cost will be VecCost*floor(TC/VF) + ScalarCost*(TC%VF). There will be
3984     // some extra overheads, but for the purpose of comparing the costs of
3985     // different VFs we can use this to compare the total loop-body cost
3986     // expected after vectorization.
3987     if (HasTail)
3988       return VectorCost * (MaxTripCount / VF) +
3989              ScalarCost * (MaxTripCount % VF);
3990     return VectorCost * divideCeil(MaxTripCount, VF);
3991   };
3992 
3993   auto RTCostA = GetCostForTC(EstimatedWidthA, CostA, A.ScalarCost);
3994   auto RTCostB = GetCostForTC(EstimatedWidthB, CostB, B.ScalarCost);
3995   return CmpFn(RTCostA, RTCostB);
3996 }
