4395 bool LoopVectorizationPlanner::isCandidateForEpilogueVectorization(
4396     ElementCount VF) const {
4397   // Cross iteration phis such as fixed-order recurrences and FMaxNum/FMinNum
4398   // reductions need special handling and are currently unsupported.
4399   if (any_of(OrigLoop->getHeader()->phis(), [&](PHINode &Phi) {
4400         if (!Legal->isReductionVariable(&Phi))
4401           return Legal->isFixedOrderRecurrence(&Phi);
4402         RecurKind Kind =
4403             Legal->getRecurrenceDescriptor(&Phi).getRecurrenceKind();
4404         return RecurrenceDescriptor::isFPMinMaxNumRecurrenceKind(Kind);
4405       }))
4406     return false;
4407 
4408   // FindLast reductions and inductions without underlying PHI require special
4409   // handling and are currently not supported for epilogue vectorization.
4410   if (hasUnsupportedHeaderPhiRecipe(getPlanFor(VF)))
4411     return false;
4412 
4413   // Phis with uses outside of the loop require special handling and are
4414   // currently unsupported.
4415   for (const auto &Entry : Legal->getInductionVars()) {
4416     // Look for uses of the value of the induction at the last iteration.
4417     Value *PostInc =
4418         Entry.first->getIncomingValueForBlock(OrigLoop->getLoopLatch());
4419     for (User *U : PostInc->users())
4420       if (!OrigLoop->contains(cast<Instruction>(U)))
4421         return false;
4422     // Look for uses of penultimate value of the induction.
4423     for (User *U : Entry.first->users())
4424       if (!OrigLoop->contains(cast<Instruction>(U)))
4425         return false;
4426   }
4427 
4428   // Epilogue vectorization code has not been auditted to ensure it handles
4429   // non-latch exits properly.  It may be fine, but it needs auditted and
4430   // tested.
4431   // TODO: Add support for loops with an early exit.
4432   if (OrigLoop->getExitingBlock() != OrigLoop->getLoopLatch())
4433     return false;
4434 
4435   return true;
4436 }
