4438 bool LoopVectorizationCostModel::isEpilogueVectorizationProfitable(
4439     const ElementCount VF, const unsigned IC) const {
4440   // FIXME: We need a much better cost-model to take different parameters such
4441   // as register pressure, code size increase and cost of extra branches into
4442   // account. For now we apply a very crude heuristic and only consider loops
4443   // with vectorization factors larger than a certain value.
4444 
4445   // Allow the target to opt out entirely.
4446   if (!TTI.preferEpilogueVectorization())
4447     return false;
4448 
4449   // We also consider epilogue vectorization unprofitable for targets that don't
4450   // consider interleaving beneficial (eg. MVE).
4451   if (TTI.getMaxInterleaveFactor(VF) <= 1)
4452     return false;
4453 
4454   unsigned MinVFThreshold = EpilogueVectorizationMinVF.getNumOccurrences() > 0
4455                                 ? EpilogueVectorizationMinVF
4456                                 : TTI.getEpilogueVectorizationMinVF();
4457   return estimateElementCount(VF * IC, VScaleForTuning) >= MinVFThreshold;
4458 }
