4596 std::pair<unsigned, unsigned>
4597 LoopVectorizationCostModel::getSmallestAndWidestTypes() {
4598   unsigned MinWidth = -1U;
4599   unsigned MaxWidth = 8;
4600   const DataLayout &DL = TheFunction->getDataLayout();
4601   // For in-loop reductions, no element types are added to ElementTypesInLoop
4602   // if there are no loads/stores in the loop. In this case, check through the
4603   // reduction variables to determine the maximum width.
4604   if (ElementTypesInLoop.empty() && !Legal->getReductionVars().empty()) {
4605     for (const auto &PhiDescriptorPair : Legal->getReductionVars()) {
4606       const RecurrenceDescriptor &RdxDesc = PhiDescriptorPair.second;
4607       // When finding the min width used by the recurrence we need to account
4608       // for casts on the input operands of the recurrence.
4609       MinWidth = std::min(
4610           MinWidth,
4611           std::min(RdxDesc.getMinWidthCastToRecurrenceTypeInBits(),
4612                    RdxDesc.getRecurrenceType()->getScalarSizeInBits()));
4613       MaxWidth = std::max(MaxWidth,
4614                           RdxDesc.getRecurrenceType()->getScalarSizeInBits());
4615     }
4616   } else {
4617     for (Type *T : ElementTypesInLoop) {
4618       MinWidth = std::min<unsigned>(
4619           MinWidth, DL.getTypeSizeInBits(T->getScalarType()).getFixedValue());
4620       MaxWidth = std::max<unsigned>(
4621           MaxWidth, DL.getTypeSizeInBits(T->getScalarType()).getFixedValue());
4622     }
4623   }
4624   return {MinWidth, MaxWidth};
4625 }
