4627 void LoopVectorizationCostModel::collectElementTypesForWidening() {
4628   ElementTypesInLoop.clear();
4629   // For each block.
4630   for (BasicBlock *BB : TheLoop->blocks()) {
4631     // For each instruction in the loop.
4632     for (Instruction &I : BB->instructionsWithoutDebug()) {
4633       Type *T = I.getType();
4634 
4635       // Skip ignored values.
4636       if (ValuesToIgnore.count(&I))
4637         continue;
4638 
4639       // Only examine Loads, Stores and PHINodes.
4640       if (!isa<LoadInst>(I) && !isa<StoreInst>(I) && !isa<PHINode>(I))
4641         continue;
4642 
4643       // Examine PHI nodes that are reduction variables. Update the type to
4644       // account for the recurrence type.
4645       if (auto *PN = dyn_cast<PHINode>(&I)) {
4646         if (!Legal->isReductionVariable(PN))
4647           continue;
4648         const RecurrenceDescriptor &RdxDesc =
4649             Legal->getRecurrenceDescriptor(PN);
4650         if (PreferInLoopReductions || useOrderedReductions(RdxDesc) ||
4651             TTI.preferInLoopReduction(RdxDesc.getRecurrenceKind(),
4652                                       RdxDesc.getRecurrenceType()))
4653           continue;
4654         T = RdxDesc.getRecurrenceType();
4655       }
4656 
4657       // Examine the stored values.
4658       if (auto *ST = dyn_cast<StoreInst>(&I))
4659         T = ST->getValueOperand()->getType();
4660 
4661       assert(T->isSized() &&
4662              "Expected the load/store/recurrence type to be sized");
4663 
4664       ElementTypesInLoop.insert(T);
4665     }
4666   }
4667 }
