4669 unsigned
4670 LoopVectorizationPlanner::selectInterleaveCount(VPlan &Plan, ElementCount VF,
4671                                                 InstructionCost LoopCost) {
4672   // -- The interleave heuristics --
4673   // We interleave the loop in order to expose ILP and reduce the loop overhead.
4674   // There are many micro-architectural considerations that we can't predict
4675   // at this level. For example, frontend pressure (on decode or fetch) due to
4676   // code size, or the number and capabilities of the execution ports.
4677   //
4678   // We use the following heuristics to select the interleave count:
4679   // 1. If the code has reductions, then we interleave to break the cross
4680   // iteration dependency.
4681   // 2. If the loop is really small, then we interleave to reduce the loop
4682   // overhead.
4683   // 3. We don't interleave if we think that we will spill registers to memory
4684   // due to the increased register pressure.
4685 
4686   // Only interleave tail-folded loops if wide lane masks are requested, as the
4687   // overhead of multiple instructions to calculate the predicate is likely
4688   // not beneficial. If a scalar epilogue is not allowed for any other reason,
4689   // do not interleave.
4690   if (!CM.isScalarEpilogueAllowed() &&
4691       !(CM.preferPredicatedLoop() && CM.useWideActiveLaneMask()))
4692     return 1;
4693 
4694   if (any_of(Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis(),
4695              IsaPred<VPCurrentIterationPHIRecipe>)) {
4696     LLVM_DEBUG(dbgs() << "LV: Loop requires variable-length step. "
4697                          "Unroll factor forced to be 1.\n");
4698     return 1;
4699   }
4700 
4701   // We used the distance for the interleave count.
4702   if (!Legal->isSafeForAnyVectorWidth())
4703     return 1;
4704 
4705   // We don't attempt to perform interleaving for loops with uncountable early
4706   // exits because the VPInstruction::AnyOf code cannot currently handle
4707   // multiple parts.
4708   if (Plan.hasEarlyExit())
4709     return 1;
4710 
4711   const bool HasReductions =
4712       any_of(Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis(),
4713              IsaPred<VPReductionPHIRecipe>);
4714 
4715   // FIXME: implement interleaving for FindLast transform correctly.
4716   if (hasFindLastReductionPhi(Plan))
4717     return 1;
4718 
4719   // If we did not calculate the cost for VF (because the user selected the VF)
4720   // then we calculate the cost of VF here.
4721   if (LoopCost == 0) {
4722     if (VF.isScalar())
4723       LoopCost = CM.expectedCost(VF);
4724     else
4725       LoopCost = cost(Plan, VF);
4726     assert(LoopCost.isValid() && "Expected to have chosen a VF with valid cost");
4727 
4728     // Loop body is free and there is no need for interleaving.
4729     if (LoopCost == 0)
4730       return 1;
4731   }
4732 
4733   VPRegisterUsage R =
4734       calculateRegisterUsageForPlan(Plan, {VF}, TTI, CM.ValuesToIgnore)[0];
4735   // We divide by these constants so assume that we have at least one
4736   // instruction that uses at least one register.
4737   for (auto &Pair : R.MaxLocalUsers) {
4738     Pair.second = std::max(Pair.second, 1U);
4739   }
4740 
4741   // We calculate the interleave count using the following formula.
4742   // Subtract the number of loop invariants from the number of available
4743   // registers. These registers are used by all of the interleaved instances.
4744   // Next, divide the remaining registers by the number of registers that is
4745   // required by the loop, in order to estimate how many parallel instances
4746   // fit without causing spills. All of this is rounded down if necessary to be
4747   // a power of two. We want power of two interleave count to simplify any
4748   // addressing operations or alignment considerations.
4749   // We also want power of two interleave counts to ensure that the induction
4750   // variable of the vector loop wraps to zero, when tail is folded by masking;
4751   // this currently happens when OptForSize, in which case IC is set to 1 above.
4752   unsigned IC = UINT_MAX;
4753 
4754   for (const auto &Pair : R.MaxLocalUsers) {
4755     unsigned TargetNumRegisters = TTI.getNumberOfRegisters(Pair.first);
4756     LLVM_DEBUG(dbgs() << "LV: The target has " << TargetNumRegisters
4757                       << " registers of "
4758                       << TTI.getRegisterClassName(Pair.first)
4759                       << " register class\n");
4760     if (VF.isScalar()) {
4761       if (ForceTargetNumScalarRegs.getNumOccurrences() > 0)
4762         TargetNumRegisters = ForceTargetNumScalarRegs;
4763     } else {
4764       if (ForceTargetNumVectorRegs.getNumOccurrences() > 0)
4765         TargetNumRegisters = ForceTargetNumVectorRegs;
4766     }
4767     unsigned MaxLocalUsers = Pair.second;
4768     unsigned LoopInvariantRegs = 0;
4769     if (R.LoopInvariantRegs.contains(Pair.first))
4770       LoopInvariantRegs = R.LoopInvariantRegs[Pair.first];
4771 
4772     unsigned TmpIC = llvm::bit_floor((TargetNumRegisters - LoopInvariantRegs) /
4773                                      MaxLocalUsers);
4774     // Don't count the induction variable as interleaved.
4775     if (EnableIndVarRegisterHeur) {
4776       TmpIC = llvm::bit_floor((TargetNumRegisters - LoopInvariantRegs - 1) /
4777                               std::max(1U, (MaxLocalUsers - 1)));
4778     }
4779 
4780     IC = std::min(IC, TmpIC);
4781   }
4782 
4783   // Clamp the interleave ranges to reasonable counts.
4784   unsigned MaxInterleaveCount = TTI.getMaxInterleaveFactor(VF);
4785 
4786   // Check if the user has overridden the max.
4787   if (VF.isScalar()) {
4788     if (ForceTargetMaxScalarInterleaveFactor.getNumOccurrences() > 0)
4789       MaxInterleaveCount = ForceTargetMaxScalarInterleaveFactor;
4790   } else {
4791     if (ForceTargetMaxVectorInterleaveFactor.getNumOccurrences() > 0)
4792       MaxInterleaveCount = ForceTargetMaxVectorInterleaveFactor;
4793   }
4794 
4795   // Try to get the exact trip count, or an estimate based on profiling data or
4796   // ConstantMax from PSE, failing that.
4797   auto BestKnownTC = getSmallBestKnownTC(PSE, OrigLoop);
