7361 // epilog loop, fix the reduction's scalar PHI node by adding the incoming value
7362 // from the main vector loop.
7363 static void fixReductionScalarResumeWhenVectorizingEpilog(
7364     VPPhi *EpiResumePhiR, PHINode &EpiResumePhi, BasicBlock *BypassBlock) {
7365   using namespace VPlanPatternMatch;
7366   // Get the VPInstruction computing the reduction result in the middle block.
7367   // The first operand may not be from the middle block if it is not connected
7368   // to the scalar preheader. In that case, there's nothing to fix.
7369   VPValue *Incoming = EpiResumePhiR->getOperand(0);
7370   match(Incoming, VPlanPatternMatch::m_ZExtOrSExt(
7371                       VPlanPatternMatch::m_VPValue(Incoming)));
7372   auto *EpiRedResult = dyn_cast<VPInstruction>(Incoming);
7373   if (!EpiRedResult)
7374     return;
7375 
7376   VPValue *BackedgeVal;
7377   bool IsFindIV = false;
7378   if (EpiRedResult->getOpcode() == VPInstruction::ComputeAnyOfResult ||
7379       EpiRedResult->getOpcode() == VPInstruction::ComputeReductionResult)
7380     BackedgeVal = EpiRedResult->getOperand(EpiRedResult->getNumOperands() - 1);
7381   else if (matchFindIVResult(EpiRedResult, m_VPValue(BackedgeVal), m_VPValue()))
