7386   auto *EpiRedHeaderPhi = cast_if_present<VPReductionPHIRecipe>(
7387       vputils::findRecipe(BackedgeVal, IsaPred<VPReductionPHIRecipe>));
7388   if (!EpiRedHeaderPhi) {
7389     match(BackedgeVal,
7390           VPlanPatternMatch::m_Select(VPlanPatternMatch::m_VPValue(),
7391                                       VPlanPatternMatch::m_VPValue(BackedgeVal),
7392                                       VPlanPatternMatch::m_VPValue()));
7393     EpiRedHeaderPhi = cast<VPReductionPHIRecipe>(
7394         vputils::findRecipe(BackedgeVal, IsaPred<VPReductionPHIRecipe>));
7395   }
