7397   Value *MainResumeValue;
7398   if (auto *VPI = dyn_cast<VPInstruction>(EpiRedHeaderPhi->getStartValue())) {
7399     assert((VPI->getOpcode() == VPInstruction::Broadcast ||
7400             VPI->getOpcode() == VPInstruction::ReductionStartVector) &&
7401            "unexpected start recipe");
7402     MainResumeValue = VPI->getOperand(0)->getUnderlyingValue();
7403   } else
7404     MainResumeValue = EpiRedHeaderPhi->getStartValue()->getUnderlyingValue();
