7420   // When fixing reductions in the epilogue loop we should already have
7421   // created a bc.merge.rdx Phi after the main vector body. Ensure that we carry
7422   // over the incoming values correctly.
7423   EpiResumePhi.setIncomingValueForBlock(
7424       BypassBlock, MainResumePhi->getIncomingValueForBlock(BypassBlock));
