4007 void LoopVectorizationPlanner::emitInvalidCostRemarks(
4008     OptimizationRemarkEmitter *ORE) {
4009   using RecipeVFPair = std::pair<VPRecipeBase *, ElementCount>;
4010   SmallVector<RecipeVFPair> InvalidCosts;
4011   for (const auto &Plan : VPlans) {
4012     for (ElementCount VF : Plan->vectorFactors()) {
4013       // The VPlan-based cost model is designed for computing vector cost.
4014       // Querying VPlan-based cost model with a scarlar VF will cause some
4015       // errors because we expect the VF is vector for most of the widen
4016       // recipes.
4017       if (VF.isScalar())
4018         continue;
4019 
4020       VPCostContext CostCtx(CM.TTI, *CM.TLI, *Plan, CM, CM.CostKind, CM.PSE,
4021                             OrigLoop);
4022       precomputeCosts(*Plan, VF, CostCtx);
4023       auto Iter = vp_depth_first_deep(Plan->getVectorLoopRegion()->getEntry());
4024       for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
4025         for (auto &R : *VPBB) {
4026           if (!R.cost(VF, CostCtx).isValid())
4027             InvalidCosts.emplace_back(&R, VF);
4028         }
4029       }
4030     }
4031   }
4032   if (InvalidCosts.empty())
4033     return;
4034 
4035   // Emit a report of VFs with invalid costs in the loop.
4036 
4037   // Group the remarks per recipe, keeping the recipe order from InvalidCosts.
4038   DenseMap<VPRecipeBase *, unsigned> Numbering;
4039   unsigned I = 0;
4040   for (auto &Pair : InvalidCosts)
4041     if (Numbering.try_emplace(Pair.first, I).second)
4042       ++I;
4043 
4044   // Sort the list, first on recipe(number) then on VF.
4045   sort(InvalidCosts, [&Numbering](RecipeVFPair &A, RecipeVFPair &B) {
4046     unsigned NA = Numbering[A.first];
4047     unsigned NB = Numbering[B.first];
4048     if (NA != NB)
4049       return NA < NB;
4050     return ElementCount::isKnownLT(A.second, B.second);
4051   });
4052 
4053   // For a list of ordered recipe-VF pairs:
4054   //   [(load, VF1), (load, VF2), (store, VF1)]
4055   // group the recipes together to emit separate remarks for:
4056   //   load  (VF1, VF2)
4057   //   store (VF1)
4058   auto Tail = ArrayRef<RecipeVFPair>(InvalidCosts);
4059   auto Subset = ArrayRef<RecipeVFPair>();
4060   do {
4061     if (Subset.empty())
4062       Subset = Tail.take_front(1);
4063 
4064     VPRecipeBase *R = Subset.front().first;
4065 
4066     unsigned Opcode =
4067         TypeSwitch<const VPRecipeBase *, unsigned>(R)
4068             .Case([](const VPHeaderPHIRecipe *R) { return Instruction::PHI; })
4069             .Case(
4070                 [](const VPWidenStoreRecipe *R) { return Instruction::Store; })
4071             .Case([](const VPWidenLoadRecipe *R) { return Instruction::Load; })
4072             .Case<VPWidenCallRecipe, VPWidenIntrinsicRecipe>(
4073                 [](const auto *R) { return Instruction::Call; })
4074             .Case<VPInstruction, VPWidenRecipe, VPReplicateRecipe,
4075                   VPWidenCastRecipe>(
4076                 [](const auto *R) { return R->getOpcode(); })
4077             .Case([](const VPInterleaveRecipe *R) {
4078               return R->getStoredValues().empty() ? Instruction::Load
4079                                                   : Instruction::Store;
4080             })
4081             .Case([](const VPReductionRecipe *R) {
4082               return RecurrenceDescriptor::getOpcode(R->getRecurrenceKind());
4083             });
4084 
4085     // If the next recipe is different, or if there are no other pairs,
4086     // emit a remark for the collated subset. e.g.
4087     //   [(load, VF1), (load, VF2))]
4088     // to emit:
4089     //  remark: invalid costs for 'load' at VF=(VF1, VF2)
4090     if (Subset == Tail || Tail[Subset.size()].first != R) {
4091       std::string OutString;
4092       raw_string_ostream OS(OutString);
4093       assert(!Subset.empty() && "Unexpected empty range");
4094       OS << "Recipe with invalid costs prevented vectorization at VF=(";
4095       for (const auto &Pair : Subset)
4096         OS << (Pair.second == Subset.front().second ? "" : ", ") << Pair.second;
4097       OS << "):";
4098       if (Opcode == Instruction::Call) {
4099         StringRef Name = "";
4100         if (auto *Int = dyn_cast<VPWidenIntrinsicRecipe>(R)) {
4101           Name = Int->getIntrinsicName();
4102         } else {
4103           auto *WidenCall = dyn_cast<VPWidenCallRecipe>(R);
4104           Function *CalledFn =
4105               WidenCall ? WidenCall->getCalledScalarFunction()
4106                         : cast<Function>(R->getOperand(R->getNumOperands() - 1)
4107                                              ->getLiveInIRValue());
4108           Name = CalledFn->getName();
4109         }
4110         OS << " call to " << Name;
4111       } else
4112         OS << " " << Instruction::getOpcodeName(Opcode);
4113       reportVectorizationInfo(OutString, "InvalidCost", ORE, OrigLoop, nullptr,
4114                               R->getDebugLoc());
4115       Tail = Tail.drop_front(Subset.size());
4116       Subset = {};
4117     } else
4118       // Grow the subset by one element
4119       Subset = Tail.take_front(Subset.size() + 1);
4120   } while (!Tail.empty());
4121 }
